// 这里是设备日志,更新添加
import {ADD_TO_TIMER} from "../actions/timer-actions"
// 基础数据
const initialState ={
	timer:[
		{time:"2018/11/8",changeTime:"下午5:06:55",shebei:"15b23c55f89s775r84saf88sz3x555s"}
	]
}
export default function(state=initialState,action){
	switch(action.type){
		case ADD_TO_TIMER:{
			return {
				...state,
				timer:[...state.timer,action.payload]
			}
		}
		default:return state
	}
}