import React, { Component } from 'react';
import "./orderRent.css"

import store from '../../store/store.js';

import Manager from "../manager/manager"

class OrderRent extends Component{
	constructor(){
		super()
		this.state={
			diviceOnList:[],
			cgg:"欢迎页"
		}
	}
	componentWillMount(){
		this.state.diviceOnList =this.props.ogg
		if (this.props.cgg!='') {
			this.state.cgg=this.props.cgg
		}

	}
	componentWillUpdate(news,olds){
		this.state.diviceOnList =news.ogg
		var index = -1;
		this.state.diviceOnList.forEach((val,ind)=>{
			if (val.name ==this.props.cgg) {
				index = ind
			};
		})
		if (index==-1) {
			this.state.diviceOnList[this.state.diviceOnList.length-1].clo = true
		}
		this.state.cgg=news.cgg
	}
	// 存储点击的小内容
	delOgg(el,istrue){
		var msg = {
			name:el,
			clo:istrue
		}
		this.props.delOgg(msg)
	}
	changeOgg(el){
		this.state.diviceOnList.map((val,ind)=>{
			val.clo = false;
			if (val.name == el) {
				this.state.diviceOnList[ind].clo =true;
			};
		})
		this.state.cgg=el
		this.setState({})
	}
	render(){
		var orderTop = this.state.diviceOnList.map((val,ind)=>{
			if (val.clo) {
				return (
				<li key={ind} className="orderRent_top_liT">
					<span onClick={this.changeOgg.bind(this,val.name)}>{val.name}</span>
					<i className="el-icon-close" onClick={this.delOgg.bind(this,val.name,val.clo)}></i>
				</li>)
			}else{
				return (
				<li key={ind} className="orderRent_top_li">
					<span onClick={this.changeOgg.bind(this,val.name)}>{val.name}</span>
					<i className="el-icon-close" onClick={this.delOgg.bind(this,val.name,val.clo)}></i>
				</li>)
			}
			
		})
		return(
			<div className="orderRent">
				<div className="orderRent_top">
					<ul className="orderRent_top_ul">
					{orderTop}
					</ul>
				</div>
				<div className="orderRent_bottom">
					<Manager cgg={this.state.cgg}></Manager>
				</div>
			</div>
		)
	}
}
export default OrderRent