import React, { Component } from 'react';
import {addTimer} from "../../../store/actions/timer-actions"
import store from "../../../store/store.js"
// 引入css样式
import "./factDist.css"

class FactDist extends Component{
	constructor(){
		super()
		this.state={
			data:[
				{time:"2018/11/8",changeTime:"下午5:06:55",shebei:"15b23c55f89s775r84saf88sz3x555s"}
			],
			msg:""
		}
	}
	componentWillMount(){
		this.state.data = store.getState().factTimer.timer
	}
	componentWillUpdate(){

	}
	render(){
		var list = this.state.data.map((val,ind)=>{
			return (
				<li key={ind}>
					<div>{val.time}</div>
					<div>{val.changeTime}</div>
					<div>{val.shebei}</div>
				</li>
			)
		})
		return (
			<div className="factDist">
				<p className="factDist_p">设立是设备日志,server于设备操作的日志</p>
				<p className="factDist_p">每次修改,都会更新这里数据,方便你管理你的设备</p>
				<p className="factDist_p2">活动日志:</p>
				<ul className="factDist_ul">
					<li>
						<div>更改日期</div>
						<div>更改时间</div>
						<div>更改设备</div>
					</li>
					{list}
				</ul>
			</div>
		)
	}
}
export default FactDist