import React, { Component } from 'react';
import Welcome from "./factManage/welcome"
import FactData from "./factManage/factData"
import AddFact from "./factManage/addFact"
import FactDist from "./factManage/factDist"

class Manager extends Component{
	constructor(){
		super()
		this.state={
			cgg:""
		}
	}
	componentWillMount(){
		this.state.cgg=this.props.cgg
	}
	componentWillUpdate(news){
		this.state.cgg=news.cgg
	}
	render(){
		var msg = this.state.cgg
		if(msg=="欢迎页"){
			return(<Welcome></Welcome>)
		}else if(msg=="设备列表") {
			return(<FactData></FactData>)
		}else if(msg=="设备添加"){
			return(<AddFact></AddFact>)
		}else if(msg=="设备日志"){
			return(<FactDist></FactDist>)
		}else if(msg=="商品列表"){
			return(<FactDist></FactDist>)
		}else if(msg=="商品添加"){
			return(<FactDist></FactDist>)
		}else if(msg=="品类列表"){
			return(<FactDist></FactDist>)
		}else if(msg=="品类添加"){
			return(<FactDist></FactDist>)
		}else if(msg=="订单列表"){
			return(<FactDist></FactDist>)
		}else if(msg=="订单添加"){
			return(<FactDist></FactDist>)
		}else if(msg=="销售统计"){
			return(<FactDist></FactDist>)
		}else if(msg=="设备统计"){
			return(<FactDist></FactDist>)
		}else if(msg=="用户日志"){
			return(<FactDist></FactDist>)
		}else{
			return(
				<div></div>
			)
		}
		
	}
}
export default Manager