import React, { Component } from 'react';
import $ from 'jquery';
import './onHome.css';
import SearchMsg from "./searchMsg"
class onHome extends Component{
	constructor(){
		super();
		this.state={
			msg:'',
			onceMsg:[]
		}	
	}
	searchText(){
		var msg = this.state.msg
		console.log()
		var _this = this
		$.ajax({
			url:"https://sp0.baidu.com/5a1Fazu8AA54nxGko9WTAnF6hhy/su",
			data:{
				wd:msg
			},
			//使用jsonp请求（不是AJAX请求了）
			dataType:"jsonp",
			//指定后台获取函数名的key
			jsonp:"cb",
			success(data){
				console.log(data.s);
				// 绘制界面
				// console.log(_this)
				_this.setState({
					onceMsg:data.s
				})
			},
		});
	}
	changed(ev){
		this.setState({
			msg:ev.target.value
		})
	}
	goReact(ev){
		console.log(ev)
		console.log(this.props)
		// this.props.router.push('/')
	}
	render(){
		// var serach = this.state.onceMsg
		// var lists=null;
		// if (serach.length) {
		// 	lists = serach.map(function(value,index){
		// 		//给唯一的key的目的:react绘制的时候重用
		// 		return <li className="searchList" key={index}>{value}</li>
		// 	})	
		// };
		return (	
			<div id="onHome">
				<p className="onHome_p"><span>简单小首页</span> 为您服务</p>
				<ul className="onHome_ul">
					<li className="onHome_ul_li">
						<p className="onHome_ul_li_div1">你可以在这里输入你要输入的<span>内容</span>,我来告诉你<span>答案</span></p>
						<div className="onHome_ul_li_div2">
							<input type="text" value={this.state.msg}  onChange={this.changed.bind(this)}/>
							<span onClick={this.searchText.bind(this)}>搜索</span>
						</div>
						<div className="onHome_ul_li_div3">
							<SearchMsg datas={this.state.onceMsg}></SearchMsg>
						</div>
					</li>
				</ul>
				<footer className="onHome_footer">
				冰哥黑科技为你服务! 
				<span> ReactBoom</span>
				</footer>
			</div>
		)
	}
}
export default onHome