import React, { Component } from 'react';
import './home.css';

import Onhome from './center/onHome';
import Onadd from './center/onAdd';
import Onsee from './center/onSee';

class Home extends Component{
	constructor(){
		super();
		this.state={
			// 通过改变值,来改变界面
			isClack:2
		}	
	}
	isClack(el){
		this.setState({
			isClack:el
		});
	}
	render(){
		var list;
		if (this.state.isClack===1) {
			list=(<Onhome></Onhome>)
		}
		if (this.state.isClack===2) {
			list=(<Onadd></Onadd>)
		}
		if (this.state.isClack===3) {
			list=(<Onsee></Onsee>)
		}
		return (	
			<div id="home">
				<nav className="homeTop">
					<div onClick={this.isClack.bind(this,1)}>主界面</div>
					<div onClick={this.isClack.bind(this,2)}>添加界面</div>
					<div onClick={this.isClack.bind(this,3)}>查看界面</div>
				</nav>
				<div className="homeCenter">{list}</div>
			</div>
		)
	}
}
export default Home