// 这里是设备列表
import {UPDATE_FACT} from "../actions/fact-actions"
import {ADD_FACT} from "../actions/fact-actions"
const initialState = {
  fact:[]
}

export default function(state=initialState,action){
	switch(action.type){
		case UPDATE_FACT:{
			return {
				...state,
				fact:action.payload
			}
		}
		case ADD_FACT:{
			return {
				...state,
				fact:[...state.fact,action.payload]
			}
		}
		default:return state
	}
}