// 这里是添加界面,左边点击时,右边显示的头部
import  { UPDATE_KAR }  from '../actions/kar-actions';


const initialState = {
  kar: [
    {
      	name:"欢迎页",
		clo:true
    },
  ]
}
export default function(state=initialState,action){
	switch(action.type){
		case UPDATE_KAR:{
			return {
				...state,
				kar:action.payload
			}
		}
		default:return state;
	}
}