import React, { Component } from 'react';
import store from '../../store/store.js';
import "./deviceList.css"


class Devicelist extends Component{
	constructor(){
		super();
		this.state={
			msg:[
			{"mog":[
				{"name":"设备列表","clo":false},
				{"name":"设备添加","clo":false},
				{"name":"设备日志","clo":false}],
			"cli":true,"id":0},
			{"mog":[
				{"name":"商品列表","clo":false},
				{"name":"商品添加","clo":false},
				{"name":"品类列表","clo":false},
				{"name":"品类添加","clo":false}],
			"cli":true,"id":1},
			{"mog":[
				{"name":"订单列表","clo":false},
				{"name":"订单添加","clo":false}],
			"cli":true,"id":2},
			{"mog":[
				{"name":"销售统计","clo":false},
				{"name":"设备统计","clo":false},
				{"name":"用户日志","clo":false}],
			"cli":true,"id":3},
			{"mog":[
				{"name":"角色管理","clo":false},
				{"name":"用户管理","clo":false},
				{"name":"菜单管理","clo":false},
				{"name":"商户管理","clo":false}],
			"cli":true,"id":4}
			],
			// 左边框最大的包涵体
			mag:["设备管理","商品管理","订单管理","数据统计","系统管理"],
			// 需要被存储的内容
			ogg:[],
		}	
	}
	// 点击后显示隐藏小内容
	onUpDown(ind){
		// 点击时,显示隐藏
		this.state.msg[ind].cli = !this.state.msg[ind].cli
		this.setState({})
	}
	// 开始阶段要进行内容绘制
	componentWillMount(){
		// this.state.ogg = store.getState().pulgKar.kar
		this.setState({
			ogg:this.props.ogg
		})
	}
	// 存储点击的小内容
	addOgg(el,istrue){
		var msg = {
			name:el,
			clo:istrue
		}
		this.props.addOgg(msg)
	}
	render(){
		var listBod;
		var listIcon;
		var listTop = this.state.mag.map((value,index) => {
			if (this.state.msg[index].cli) {
				listIcon = (<i className="el-icon-arrow-up"></i>)
				listBod = this.state.msg[index].mog.map((val,ind)=>{
					return (<li key={ind} onClick={this.addOgg.bind(this,val.name,val.clo)}>{val.name}</li>)
				})
			}else{
				listBod =null
				listIcon = (<i className="el-icon-arrow-down"></i>)
			}
			
			return (<li key={index}  className="onAdd_center_left_li">
						<div className="onAdd_center_left_ul_div1" onClick={this.onUpDown.bind(this,index)}>
							<div className="onAdd_center_left_ul_div1_span1"><i className="el-icon-menu"></i></div>
							<div className="onAdd_center_left_ul_div1_span2">{value}</div>
							<div className="onAdd_center_left_ul_div1_span3">{listIcon}</div>
						</div>
						<ol className="onAdd_center_left_ul_div2">
							{listBod}
						</ol>
					</li>)
		})
		
		return (	
			<ul className="onAdd_center_left_ul">
				{listTop}
			</ul>
		)
	}
}
export default Devicelist	