// 增加产品
export const ADD_TO_PRODUCTS ="ADD_TO_PRODUCTS"
export function addProducts(product,prise,overhid){
	return {
		type:ADD_TO_PRODUCTS,
		content:{product,prise,overhid}
	}
}
// 更新产品
export const UPDATE_PRODUCTS = 'UPDATE_PRODUCTS';
export function updateProducts(product, quantity, unitCost) {
  return {
    type: UPDATE_PRODUCTS,
    content: {
      product,
      quantity,
      unitCost
    }
  }
}
//删除产品
export const DEL_PRODUCTS="DEL_PRODUCTS";
export function delProducts(product){
	return{
		type:DEL_PRODUCTS,
		content:{
			product
		}
	}
}