// src/reducers/products-reducer.js


// 引入type类型
import {ADD_TO_PRODUCTS} from "../actions/products-actions"
import {UPDATE_PRODUCTS} from "../actions/products-actions"
import {DEL_PRODUCTS} from "../actions/products-actions"

const initialState ={
  products:[
    {
      product:"orange",
      prise:20,
      overhid:999
    },
    {
      product:"apple",
      prise:20,
      overhid:998
    }
  ]
}

export default function(state=initialState, action) {
  switch(action.type){
  	case ADD_TO_PRODUCTS:{
  		return {
  			...state,
  			products:[...state.products,action.content]
  		}
  	}
  	case UPDATE_PRODUCTS:{
  		return {
  			...state,
  			products:state.products.map((val)=>{return val.product === action.content.product ? action.content :val})
  		}
  	}
  	case DEL_PRODUCTS:{
  		return {
  			...state,
  			products:state.products.filter((val)=>{return val.product !== action.content.product})
  		}
  	}
  	default:
  		return state
  }
}