import React, { Component } from 'react';
import "./addFact.css"
// 引入设备列表添加方法
import {addFact} from "../../../store/actions/fact-actions"
// 引入设备日志添加方法
import {addTimer} from "../../../store/actions/timer-actions"
// 引入公用属性库
import store from "../../../store/store.js"

class AddFact extends Component{
	constructor(){
		super()
		this.state={
			data:{},
			msg:""
		}
		this.address = React.createRef()
		this.orderPhone = React.createRef()
		this.from = React.createRef()
		this.orderId = React.createRef()
	}
	componentWillMount(){

	}
	componentWillUpdate(){

	}
	addFact(){
		var shebei ="15b23c55f89s775r84saf88sz3x555s"
		var timer =new Date().toLocaleDateString()
		var yanzheng =""
		var address = this.address.current.value
		var orderPhone = this.orderPhone.current.value
		var from = this.from.current.value
		var orderId = this.orderId.current.value
		var changeTime =new Date().toLocaleTimeString()
		// 添加设备列表
		var obj = {
			shebei:shebei,
			timer:timer,
			yanzheng:yanzheng,
			address:address,
			orderPhone:orderPhone,
			from:from,
			orderId:orderId,
			changeTime:changeTime
		}
		store.dispatch(addFact(obj))


		// {time:"2018/11/8",changeTime:"下午5:06:55",shebei:"15b23c55f89s775r84saf88sz3x555s"}
		// 添加活动日志
		var addFactDist = {
			time:timer,
			changeTime:changeTime,
			shebei:shebei
		}
		store.dispatch(addTimer(addFactDist))

		this.clearFact()

	}
	clearFact(){
		this.address.current.value=""
		this.orderPhone.current.value=""
		this.from.current.value=""
		this.orderId.current.value=""
	}
	render(){
		
		return (
			<div className="factData">
				<div className="addFact_div1">
					<p><i className="el-icon-star-off"></i><input type="text" placeholder="mac地址 (必填)" ref={this.address}/></p>
					<p><i className="el-icon-search"></i><input type="text" placeholder="订单号 (必填)" ref={this.orderPhone}/></p>
					<p><i className="el-icon-more"></i><input type="text" placeholder="平台类型 (必填)" ref={this.from}/></p>
					<p><i className="el-icon-date"></i><input type="text" placeholder="产品ID (必填)" ref={this.orderId}/></p>
					<div className="factData_div1_p5">
						<div onClick={this.addFact.bind(this)}>提交</div>
						<div onClick={this.clearFact.bind(this)}>重置</div>
					</div>
				</div>
			</div>)
	}
}
export default AddFact