import React, { Component } from 'react';
import Devicelist from "../pulg/deviceList"
import Onderent from "../pulg/orderRent"
import "./onAdd.css"

import store from '../../store/store.js';
import { updateKar }  from '../../store/actions/kar-actions';

class onAdd extends Component{
	constructor(){
		super();
		this.state={
			// 需要被存储的内容
			ogg:[],
			cgg:""
		}	
	}
	// 开始阶段要进行内容绘制
	componentWillMount(){
		this.state.ogg = store.getState().pulgKar.kar
	}
	componentWillUpdate(news){
		this.state.ogg = store.getState().pulgKar.kar

	}
	addOgg(msg){
		// 查询更改
		this.state.ogg=this.state.ogg.filter(val=>val.name !== msg.name)
		// 添加时,要把原文改为缺失
		this.state.ogg.map(val=>{
			val.clo=false
		})
		// 把当前的赋值为true
		msg.clo=true
		this.state.ogg.push(msg)
		this.state.cgg = msg.name
		this.setState({})

		// 存入公用属性
		store.dispatch(updateKar(this.state.ogg));
		// 取出公用属性,并进行查看
	}
	delOgg(msg){
		if (msg.name == this.state.cgg&&this.state.ogg.length>1) {
			this.state.cgg = this.state.ogg[this.state.ogg.length-2].name
		}else{
			this.state.cgg =this.state.ogg[0].name
		}
		this.state.ogg=this.state.ogg.filter(val=>val.name !== msg.name)
		this.setState({})
		// 存入公用属性
		store.dispatch(updateKar(this.state.ogg));
		// 取出公用属性,并进行查看
	}
	render(){
		return (	
			<div className="onAdd_center">
				<div className="onAdd_center_left">
					<Devicelist addOgg={this.addOgg.bind(this)} ogg={this.state.ogg}></Devicelist>
				</div>
				<div className="onAdd_center_right">
					<Onderent delOgg={this.delOgg.bind(this)} ogg={this.state.ogg} cgg={this.state.cgg}></Onderent>
				</div>
			</div>
		)
	}
}
export default onAdd