import React, { Component } from 'react';
import "./factData.css"
// 添加公用属性方法
import {updateFact} from "../../../store/actions/fact-actions"
import {addTimer} from "../../../store/actions/timer-actions"
import store from "../../../store/store.js"

class FactData extends Component{
	constructor(){
		super()
		this.state={
			data:[
				{shebei:"123",timer:"123",yanzheng:"123",address:"123",orderPhone:"123",from:"123",orderId:"123",changeTime:"123"}
			],
			msg:"",
		}
		this.shebei = React.createRef()
		this.timer = React.createRef()
		this.yanzheng = React.createRef()
		this.address = React.createRef()
		this.orderPhone = React.createRef()
		this.orderId = React.createRef()
	}
	componentWillMount(){
		this.state.data = store.getState().factData.fact
	}
	componentWillUpdate(){
		this.state.data = store.getState().factData.fact
	}
	textPush(){
		// 添加设备
		var shebei =this.shebei.current.value
		var timer =this.timer.current.value
		var yanzheng =this.yanzheng.current.value
		var address =this.address.current.value
		var orderPhone =this.orderPhone.current.value
		var orderId =this.orderId.current.value
		var changeTime =new Date().toLocaleTimeString()
		var obj = {shebei:shebei,
			timer:timer,
			yanzheng:yanzheng,
			address:address,
			orderPhone:orderPhone,
			from:"Andrios",
			orderId:orderId,
			changeTime:changeTime}
		this.state.data.push(obj)
		store.dispatch(updateFact(this.state.data));

		// 添加活动日志
		var activeTime =new Date().toLocaleDateString()
		var addFactDist = {
			time:activeTime,
			changeTime:changeTime,
			shebei:shebei
		}
		// {time:"2018/11/8",changeTime:"下午5:06:55",shebei:"15b23c55f89s775r84saf88sz3x555s"}
		store.dispatch(addTimer(addFactDist))

		// 存储并清空
		this.setState({})
		this.textAlignt()
	}
	textAlignt(){
		this.shebei.current.value =""
		this.timer.current.value =""
		this.yanzheng.current.value =""
		this.address.current.value =""
		this.orderPhone.current.value =""
		this.orderId.current.value =""
	}
	render(){
		var list=this.state.data.map((val,ind)=>{
			return (<li key={ind}>
					<div>{val.shebei}</div>
					<div>{val.timer}</div>
					<div>{val.yanzheng}</div>
					<div>{val.address}</div>
					<div>{val.orderPhone}</div>
					<div>{val.from}</div>
					<div>{val.orderId}</div>
					<div>{val.changeTime}</div>
				</li>)
		})
		return (
			<div className="factData">
				<div className="factData_div1">
					<p className="factData_div1_p1"><input type="text" ref={this.shebei} placeholder="请输入设备编号" /></p>
					<p className="factData_div1_p2"><input type="text" ref={this.timer} placeholder="请输入日期" /><span>今天</span><span>昨天</span><span>最近七天</span><span>最近30天</span></p>
					<p className="factData_div1_p3"><input type="text" placeholder="请输入校验码" ref={this.yanzheng} />
					<input type="text" placeholder="请输入mac地址" ref={this.address} /></p>
					<p className="factData_div1_p4"><input type="text" placeholder="请输入订单号" ref={this.orderPhone} />
					<input type="text" placeholder="请输入产品id" ref={this.orderId} /></p>
					<div className="factData_div1_p5"><div onClick={this.textPush.bind(this)} >提交</div><div onClick={this.textAlignt.bind(this)}>重置</div></div>
				</div>
				<ul className="factData_div2">
					<li>
						<div>编号</div>
						<div>创建时间</div>
						<div>校验码</div>
						<div>mac地址</div>
						<div>订单号</div>
						<div>平台类型</div>
						<div>产品id</div>
						<div>修改时间</div>
					</li>
					{list}
				</ul>
			</div>
		)
		// return结束
	}
}
export default FactData